         method: 'POST',
         headers: { 'Content-Type': 'application/json' },
         body: JSON.stringify({ ...currentConfig, printerName, paperWidth, autoPrint, fontSize })
       });
       setMsg('Salvo!');
       setTimeout(() => setMsg(''), 2000);
