app.post('/api/restore-db', async (req, res) => {
    console.log("Iniciando restauração de banco de dados físico...");

    const restorePath = path.join(userDataPath, 'sisfila_restoring.db');
    const writeStream = fs.createWriteStream(restorePath);

    // Pipe the request body (binary) directly to file
    req.pipe(writeStream);

    writeStream.on('finish', async () => {
        try {
            console.log("Upload concluído. Substituindo banco...");

            // 1. Close existing DB connection to unlock file
            if (db) {
                await db.close();
                console.log("Banco fechado.");
            }

            // 2. Wait a moment for OS to release lock (Windows specific safety)
            setTimeout(async () => {
                try {
                    // 3. Backup current DB just in case (optional, but safe)
                    // fs.copyFileSync(DB_PATH, DB_PATH + '.bak'); 

                    // 4. Overwrite DB
                    // Try to delete WAL files if they exist to prevent corruption
                    if (fs.existsSync(DB_PATH + '-wal')) fs.unlinkSync(DB_PATH + '-wal');
                    if (fs.existsSync(DB_PATH + '-shm')) fs.unlinkSync(DB_PATH + '-shm');

                    // Move restored file to main DB path
                    fs.copyFileSync(restorePath, DB_PATH);
                    fs.unlinkSync(restorePath); // clean up temp

                    console.log("Arquivo substituído com sucesso.");

                    // 5. Reopen DB
                    await openDB();

                    // 6. Notify clients to reload
                    io.emit('sync-update', { type: 'RESET' });

                    res.json({ success: true });
                } catch (err) {
                    console.error("Erro crítico ao substituir arquivo DB:", err);
                    // Try to reopen old db if fail
                    await openDB();
                    res.status(500).json({ success: false, message: "Erro ao substituir arquivo." });
                }
            }, 1000);

        } catch (e) {
            console.error(e);
            res.status(500).json({ success: false });
        }
    });

    writeStream.on('error', (err) => {
        console.error("Erro no stream de upload:", err);
        res.status(500).json({ success: false });
    });
});

