        tickets, 
        services: services.map(s => ({...s, active: !!s.active})), 
        users: users.map(u => ({...u, active: !!u.active})) 
    });

    socket.on('update-tickets', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        try {
            await db.run("BEGIN TRANSACTION");
            for (const t of items) {
                await db.run(`
                    INSERT INTO tickets (id, displayId, serviceId, serviceName, priority, status, createdAt, calledAt, startedAt, finishedAt, attendantName, deskNumber) 
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    ON CONFLICT(id) DO UPDATE SET
                    status=?, calledAt=?, startedAt=?, finishedAt=?, attendantName=?, deskNumber=?
                `, [
                    t.id, t.displayId, t.serviceId, t.serviceName, t.priority, t.status, t.createdAt, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber,
                    t.status, t.calledAt, t.startedAt, t.finishedAt, t.attendantName, t.deskNumber
                ]);
            }
            await db.run("COMMIT");
            socket.broadcast.emit('sync-update', { type: 'TICKETS', data: data });
        } catch(e) {
            console.error("Erro update-tickets", e);
            await db.run("ROLLBACK");
        }
    });

    socket.on('update-services', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        try {
            await db.run("BEGIN TRANSACTION");
            for (const s of items) {
                await db.run("INSERT INTO services (id, name, active) VALUES (?, ?, ?) ON CONFLICT(id) DO UPDATE SET name=?, active=?", 
                    [s.id, s.name, 1, s.name, 1]);
            }
            await db.run("COMMIT");
            socket.broadcast.emit('sync-update', { type: 'SERVICES', data: data });
        } catch(e) { await db.run("ROLLBACK"); }
    });

    socket.on('delete-service', async (id) => {
        await db.run("DELETE FROM services WHERE id = ?", [id]);
        socket.broadcast.emit('sync-delete-service', id);
    });

    socket.on('update-users', async (data) => {
        const items = Array.isArray(data) ? data : [data];
        try {
            await db.run("BEGIN TRANSACTION");
            for (const u of items) {
                await db.run(`
