      console.error("PDF Error", err);
      setIsGeneratingPdf(false);
    });
  };

  // --- Helpers for Statistics ---

  const calculateAverageTime = (tickets: Ticket[], type: 'wait' | 'service') => {
    let total = 0;
    let count = 0;

    tickets.forEach(t => {
      if (type === 'wait' && t.calledAt && t.createdAt) {
        total += (t.calledAt - t.createdAt);
        count++;
      } else if (type === 'service' && t.finishedAt && t.startedAt) {
        total += (t.finishedAt - t.startedAt);
        count++;
      }
    });

    if (count === 0) return "0 min";
    const minutes = Math.floor((total / count) / 60000);
    const seconds = Math.floor(((total / count) % 60000) / 1000);
    return `${minutes}m ${seconds}s`;
