const PrinterTab = () => {
  const [printerName, setPrinterName] = useState('');
  const [availablePrinters, setAvailablePrinters] = useState<string[]>([]);
  const [paperWidth, setPaperWidth] = useState('80');
  const [autoPrint, setAutoPrint] = useState(true);
  const [fontSize, setFontSize] = useState('2');
  const [msg, setMsg] = useState('');

  useEffect(() => {
    fetch('/api/printer-config').then(r=>r.json()).then(data => {
        if(data.printerName) setPrinterName(data.printerName);
        if(data.paperWidth) setPaperWidth(data.paperWidth.replace('mm', ''));
        if(data.fontSize) setFontSize(data.fontSize);
        setAutoPrint(!!data.autoPrint);
    }).catch(()=>{});

    fetch('/api/printers').then(r=>r.json()).then(data => {
         if (Array.isArray(data)) setAvailablePrinters(data);
    }).catch(()=>{});
  }, []);

  const handleSave = async () => {
    try {
       const currentRes = await fetch('/api/printer-config');
       const currentConfig = await currentRes.json();
       await fetch('/api/printer-config', {
         method: 'POST',
         headers: { 'Content-Type': 'application/json' },
         body: JSON.stringify({ ...currentConfig, printerName, paperWidth, autoPrint, fontSize })
       });
       setMsg('Salvo!');
       setTimeout(() => setMsg(''), 2000);
    } catch(e) { setMsg('Erro'); }
  };

  return (
    <div className="animate-fade-in max-w-lg p-4">
       <div className="space-y-6">
          <div>
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Impressora</label>
            <select value={printerName} onChange={e => setPrinterName(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-3 outline-none text-slate-900 dark:text-white text-base">
              <option value="">Selecione...</option>
              {availablePrinters.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <div>
               <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Largura (mm)</label>
               <input type="number" value={paperWidth} onChange={e => setPaperWidth(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-3 outline-none text-slate-900 dark:text-white text-base" placeholder="80" />
            </div>
            <div>
               <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Fonte (1-8)</label>
               <input type="number" min="1" max="8" value={fontSize} onChange={e => setFontSize(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-3 outline-none text-slate-900 dark:text-white text-base" placeholder="2" />
            </div>
          </div>

          <label className="flex items-center gap-3 cursor-pointer text-base bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg border border-slate-200 dark:border-slate-700">
             <input type="checkbox" checked={autoPrint} onChange={e => setAutoPrint(e.target.checked)} className="w-5 h-5 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" />
             <span className="text-slate-700 dark:text-slate-300 font-medium">Imprimir automaticamente ao emitir senha</span>
          </label>

          <div className="flex items-center gap-4 pt-2">
            <button onClick={handleSave} className="bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 px-8 rounded-lg text-sm transition-colors shadow-md">Salvar Configuração</button>
            {msg && <span className="text-emerald-500 text-sm font-bold">{msg}</span>}
          </div>
       </div>
    </div>
  );
};

const RegisterTab = ({ onRefresh, onNavigateHome }: { onRefresh?: () => void, onNavigateHome?: () => void }) => {
  const [client, setClient] = useState('');
  const [email, setEmail] = useState('');
  const [document, setDocument] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [city, setCity] = useState('');
  const [logo, setLogo] = useState(''); 
  const [saveMessage, setSaveMessage] = useState('');

  React.useEffect(() => {
    fetch('/api/license').then(r=>r.json()).then(data => {
        if(data.clientName) setClient(data.clientName);
        if(data.clientEmail) setEmail(data.clientEmail);
        if(data.clientDocument) setDocument(data.clientDocument);
        if(data.clientPhone) setPhone(data.clientPhone);
        if(data.clientAddress) setAddress(data.clientAddress);
        if(data.clientCity) setCity(data.clientCity);
        if(data.clientLogo) setLogo(data.clientLogo);
    }).catch(()=>{});
  }, []);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) return alert("Máximo 2MB");
      const reader = new FileReader();
      reader.onloadend = () => setLogo(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSaveClientInfo = async () => {
    try {
      const res = await fetch('/api/client-info', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ clientName: client, clientEmail: email, clientDocument: document, clientPhone: phone, clientAddress: address, clientCity: city, clientLogo: logo })
      });
      if ((await res.json()).success) {
        setSaveMessage('Salvo!');
        if(onRefresh) onRefresh(); 
        setTimeout(() => setSaveMessage(''), 2000);
      }
    } catch (e) { setSaveMessage('Erro.'); }
  };

  return (
    <div className="p-8 animate-fade-in">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="col-span-1">
              <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2 uppercase">Logo da Empresa</label>
              <div className="border-2 border-dashed border-slate-300 dark:border-slate-600 rounded-xl p-4 flex flex-col items-center justify-center text-center h-48 relative bg-slate-50 dark:bg-slate-900/50 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                 {logo ? (
                   <>
                     <img src={logo} alt="Preview" className="max-h-36 max-w-full object-contain" />
                     <button onClick={() => setLogo('')} className="absolute top-2 right-2 bg-red-500 text-white p-1.5 rounded-full hover:bg-red-600 shadow"><X size={14} /></button>
                   </>
                 ) : (
                   <div className="text-slate-400">
                     <ImageIcon size={40} className="mx-auto mb-2" />
                     <p className="text-sm font-bold">Clique para enviar</p>
                     <p className="text-xs">Recomendado: PNG Transparente</p>
                   </div>
                 )}
                 <input type="file" accept="image/*" onChange={handleLogoUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
              </div>
            </div>
            <div className="col-span-2 space-y-5">
               <div className="grid grid-cols-2 gap-5">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">Nome Fantasia / Razão Social</label>
                    <input value={client} onChange={e => setClient(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1">CNPJ / CPF</label>
                    <input value={document} onChange={e => setDocument(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" />
                  </div>
               </div>
               <div className="grid grid-cols-2 gap-5">
                 <div>
                   <label className="block text-xs font-bold text-slate-500 mb-1">E-mail de Contato</label>
                   <input value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" type="email" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-500 mb-1">Telefone / WhatsApp</label>
                   <input value={phone} onChange={e => setPhone(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" />
                 </div>
               </div>
               <div className="grid grid-cols-2 gap-5">
                 <div>
                   <label className="block text-xs font-bold text-slate-500 mb-1">Cidade</label>
                   <input value={city} onChange={e => setCity(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" />
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-slate-500 mb-1">Endereço Completo</label>
                   <input value={address} onChange={e => setAddress(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-2.5 text-sm outline-none dark:text-white focus:border-indigo-500" />
                 </div>
