const LicenseTab = () => {
  const [key, setKey] = useState('');
  const [status, setStatus] = useState<any>(null);
  const [message, setMessage] = useState('');

  React.useEffect(() => {
    fetch('/api/license').then(r=>r.json()).then(setStatus).catch(()=>{});
  }, []);

  const handleActivate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('/api/license', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ key }) });
      const data = await res.json();
      if (data.success) {
        setMessage(data.message || 'Sistema ativado!');
        fetch('/api/license').then(r=>r.json()).then(setStatus);
        setKey('');
      } else { setMessage('Erro: ' + data.message); }
    } catch (error) { setMessage('Erro de conexão.'); }
  };

  const isLicenseActive = status?.hasLicense;

  return (
    <div className="p-8 animate-fade-in max-w-2xl">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 flex items-center gap-2"><Lock size={24} /> Licenciamento e Ativação</h3>

      {status && (
          <div className="mb-8 p-6 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
             <div className="grid grid-cols-2 gap-8">
                <div>
                  <p className="text-xs text-slate-500 uppercase font-bold mb-1">Status Atual</p>
                  <p className={`text-xl font-black ${isLicenseActive ? 'text-emerald-600' : 'text-yellow-600'}`}>{isLicenseActive ? 'ATIVADO' : 'TRIAL (TESTE)'}</p>
                </div>

                {isLicenseActive && status.licenseExpiryDate && (
                  <>
                    <div>
                       <p className="text-xs text-slate-500 uppercase font-bold flex items-center gap-1 mb-1">Vencimento</p>
                       <p className="text-xl font-bold text-slate-700 dark:text-slate-200">
                         {new Date(status.licenseExpiryDate).toLocaleDateString('pt-BR')}
                       </p>
                    </div>
                  </>
                )}

                <div className="col-span-2 border-t border-slate-200 dark:border-slate-700 pt-4">
                    <p className="text-xs text-slate-500 uppercase font-bold mb-1">Dias Restantes</p>
                    <p className="text-2xl font-black text-indigo-600 dark:text-indigo-400">
                        {status.trialDaysLeft} dias
                    </p>
                </div>
             </div>
          </div>
      )}

      <div>
        <h4 className="text-base font-bold text-slate-700 dark:text-slate-300 mb-2">
            {isLicenseActive ? 'Renovar / Estender Licença' : 'Ativar Sistema'}
        </h4>
        <p className="text-sm text-slate-500 mb-4">
            {isLicenseActive ? 'Deseja adicionar mais tempo ao seu plano? Insira a nova chave abaixo.' : 'Sistema bloqueado ou em teste. Insira sua chave para desbloquear.'}
        </p>

        <form onSubmit={handleActivate} className="flex gap-3">
           <input required value={key} onChange={e => setKey(e.target.value)} placeholder="SIS-XXXX-XXXX-XXXX" className="flex-1 bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg px-4 py-3 text-base outline-none dark:text-white font-mono uppercase tracking-widest" />
           <button type="submit" className={`text-white font-bold py-3 px-8 rounded-lg text-sm shadow-md transition-transform hover:scale-105 ${isLicenseActive ? 'bg-indigo-600 hover:bg-indigo-500' : 'bg-emerald-600 hover:bg-emerald-500'}`}>
              {isLicenseActive ? 'ADICIONAR DIAS' : 'ATIVAR AGORA'}
           </button>
        </form>
        {message && <p className="mt-4 text-sm font-bold text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20 p-2 rounded border border-emerald-200 dark:border-emerald-900">{message}</p>}
      </div>
    </div>
  );
};

const SystemTab = ({ onResetSystem }: { onResetSystem?: () => void }) => {
  const [subTab, setSubTab] = useState<'general' | 'printer' | 'layout' | 'license'>('general');
  const [restoreMessage, setRestoreMessage] = useState('');
  const [isUploading, setIsUploading] = useState(false);

  // Restore DB File directly
  const handleRestoreBackup = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && confirm("ATENÇÃO: Você está prestes a substituir o banco de dados inteiro.\nTodos os dados atuais serão perdidos.\nO sistema será reiniciado.\n\nDeseja continuar?")) {
      setIsUploading(true);
      const formData = new FormData();
      formData.append('file', file); // Embora backend use pipe raw, isso é útil se mudar

      try {
        // Envia como binary stream ou FormData (o servidor foi atualizado para raw stream se Content-Type for octet-stream, ou form-data)
        // Vamos usar raw stream com header customizado para simplificar no backend sem multer
        const res = await fetch('/api/restore-db', { 
            method: 'POST', 
            headers: {
                'Content-Type': 'application/octet-stream' 
            },
            body: file 
        });

        if ((await res.json()).success) { 
             setRestoreMessage('Sucesso! Reiniciando...'); 
             setTimeout(() => window.location.reload(), 2000); 
        } else { 
             setRestoreMessage('Erro no upload.'); 
        }
      } catch (err) { 
          setRestoreMessage('Erro de conexão.'); 
      } finally {
          setIsUploading(false);
      }
    }
  };

  return (
    <div className="flex flex-col md:flex-row h-[550px]">
        {/* Sidebar */}
        <div className="md:w-52 border-b md:border-b-0 md:border-r border-slate-200 dark:border-slate-700 p-4 flex flex-row md:flex-col gap-2 overflow-x-auto">
           {[
               {id:'general', icon:Cpu, l:'Geral'},
               {id:'printer', icon:Printer, l:'Impressão'},
               {id:'layout', icon:LayoutTemplate, l:'Layout'},
               {id:'license', icon:Key, l:'Licença'}
           ].map(t => (
               <button 
                 key={t.id}
                 onClick={() => setSubTab(t.id as any)}
                 className={`px-4 py-3 text-left rounded-lg text-sm font-bold flex items-center gap-3 transition-colors ${subTab === t.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}
               >
                 <t.icon size={18} /> {t.l}
               </button>
           ))}
        </div>

        {/* Content */}
        <div className="flex-1 p-6 overflow-y-auto">
          {subTab === 'general' && (
            <div className="space-y-8 animate-fade-in max-w-md">

              <div>
                  <h3 className="text-base font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2"><Database size={20} className="text-indigo-500"/> Banco de Dados (SQLite)</h3>

                  <div className="grid grid-cols-1 gap-6">
                     {/* BACKUP CARD */}
                     <div className="bg-gradient-to-br from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 border border-blue-200 dark:border-blue-800 rounded-xl p-5 shadow-sm relative overflow-hidden group hover:shadow-md transition-all">
                         <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                             <Archive size={48} className="text-blue-600 dark:text-blue-400" />
                         </div>
                         <h4 className="text-blue-800 dark:text-blue-300 font-bold text-base mb-1">Backup Completo (.db)</h4>
                         <p className="text-blue-600 dark:text-blue-400 text-sm mb-4 leading-relaxed">
                             Baixa o arquivo físico do banco de dados (sisfila.db). Contém todos os dados e configurações.
                         </p>
                         <button onClick={() => window.location.href = '/api/backup-db'} className="bg-blue-600 hover:bg-blue-500 text-white py-2.5 px-6 rounded-lg text-sm font-bold flex items-center gap-2 transition-colors shadow">
                             <Download size={16} /> Baixar Banco de Dados
                         </button>
                     </div>

                     {/* RESTORE CARD */}
                     <div className="bg-gradient-to-br from-amber-50 to-orange-50 dark:from-amber-900/20 dark:to-orange-900/20 border border-amber-200 dark:border-amber-800 rounded-xl p-5 shadow-sm relative overflow-hidden group hover:shadow-md transition-all">
                         <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                             <RefreshCw size={48} className="text-amber-600 dark:text-amber-400" />
                         </div>
                         <h4 className="text-amber-800 dark:text-amber-300 font-bold text-base mb-1">Restaurar Banco (.db)</h4>
                         <p className="text-amber-600 dark:text-amber-400 text-sm mb-4 leading-relaxed">
                             Envia um arquivo .db para substituir o atual. <br/><span className="font-bold">Cuidado:</span> Isso apagará os dados atuais.
                         </p>
                         <div className="relative inline-block">
                            <button className="bg-amber-600 hover:bg-amber-500 text-white py-2.5 px-6 rounded-lg text-sm font-bold flex items-center gap-2 transition-colors shadow" disabled={isUploading}>
                                <UploadCloud size={16} /> {isUploading ? 'Enviando...' : 'Carregar Arquivo .db'}
                            </button>
                            <input type="file" accept=".db,.sqlite,.sqlite3" onChange={handleRestoreBackup} className="absolute inset-0 opacity-0 cursor-pointer" disabled={isUploading} />
                         </div>
                         {restoreMessage && <p className="text-sm mt-2 font-bold text-emerald-600">{restoreMessage}</p>}
                     </div>
                  </div>
              </div>

              <div className="border-t border-slate-200 dark:border-slate-700 pt-6">
                <h3 className="text-sm font-bold text-red-600 dark:text-red-400 mb-3 flex items-center gap-2 uppercase"><AlertOctagon size={16}/> Zona de Perigo</h3>
                <button onClick={onResetSystem} className="bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 px-6 py-3 rounded-lg text-sm font-bold w-full transition-colors">
                    Zerar Sistema de Fábrica
                </button>
              </div>

            </div>
          )}
          {subTab === 'printer' && <PrinterTab />}
          {subTab === 'layout' && <LayoutTab />}
          {subTab === 'license' && <LicenseTab />}
        </div>
    </div>
  );
}

